import React from "react";
import { Navigate, useLocation } from "react-router-dom";

// TODO: replace with real auth state from context or API
const fakeAuth = {
  isAuthenticated: true,
  hasFinishedOnboarding: true
};

export default function ProtectedRoute({ children, requireOnboardingComplete = true }) {
  const location = useLocation();

  if (!fakeAuth.isAuthenticated) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  if (requireOnboardingComplete && !fakeAuth.hasFinishedOnboarding) {
    return <Navigate to="/setup/fleet-partner-profile" replace />;
  }

  return children;
}
